import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListResourcesRequestSchema,
  ListToolsRequestSchema,
  ReadResourceRequestSchema
} from "@modelcontextprotocol/sdk/types.js";

// Instantiate server
const server = new Server(
  {
    name: "diagnostic-server",
    version: "1.0.0"
  },
  {
    capabilities: {
      resources: {},
      tools: {}
    }
  }
);

// List resources handler
server.setRequestHandler(ListResourcesRequestSchema, async () => {
  return {
    resources: [
      {
        uri: "diagnostic://metrics",
        name: "System Performance Metrics",
        mimeType: "application/json",
        description: "Live system diagnostic statistics"
      }
    ]
  };
});

// Read resource handler
server.setRequestHandler(ReadResourceRequestSchema, async (request) => {
  if (request.params.uri === "diagnostic://metrics") {
    return {
      contents: [
        {
          uri: request.params.uri,
          mimeType: "application/json",
          text: JSON.stringify({
            status: "HEALTHY",
            cpu_usage_pct: 12.5,
            memory_free_gb: 8.4,
            timestamp: new Date().toISOString()
          })
        }
      ]
    };
  }
  throw new Error("Resource not found");
});

// List tools handler
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "echo_diagnostics",
        description: "Echoes back status metrics with custom user label",
        inputSchema: {
          type: "object",
          properties: {
            label: {
              type: "string",
              description: "A custom label for the audit logs"
            }
          },
          required: ["label"]
        }
      }
    ]
  };
});

// Call tool handler
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "echo_diagnostics") {
    const label = request.params.arguments?.label || "default";
    return {
      content: [
        {
          type: "text",
          text: `Diagnostics generated with label: [${label}]. All systems nominal.`
        }
      ]
    };
  }
  throw new Error("Tool not found");
});

// Start the server
async function run() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Diagnostic MCP Server running on stdio");
}

run().catch((error) => {
  console.error("Fatal error:", error);
  process.exit(1);
});

from mcp.server.fastmcp import FastMCP

# Initialize FastMCP Server
mcp = FastMCP("Calculators")

@mcp.tool()
def add_numbers(a: int, b: int) -> str:
    """Adds two integers and returns the formatted sum."""
    return f"The sum of {a} and {b} is {a + b}"

@mcp.resource("config://app")
def get_config() -> str:
    """Returns application configuration file data."""
    return "app_version=1.0.0\nenvironment=development\ndebug_enabled=true"

if __name__ == "__main__":
    mcp.run()

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListResourcesRequestSchema,
  ListToolsRequestSchema,
  ReadResourceRequestSchema
} from "@modelcontextprotocol/sdk/types.js";
import pg from "pg";

const { Pool } = pg;

// Initialize db pool using environment configuration
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  statement_timeout: 500 // Enforce statement execution limits
});

const server = new Server(
  {
    name: "secure-postgres-mcp",
    version: "1.0.0"
  },
  {
    capabilities: {
      resources: {},
      tools: {}
    }
  }
);

// Expose dynamic schema as resource
server.setRequestHandler(ListResourcesRequestSchema, async () => {
  return {
    resources: [
      {
        uri: "postgres://schema/customer_summary",
        name: "Customer Summary Table Schema",
        mimeType: "application/json",
        description: "Schema layout and columns of the customer_summary table"
      }
    ]
  };
});

// Read schema metadata
server.setRequestHandler(ReadResourceRequestSchema, async (request) => {
  if (request.params.uri === "postgres://schema/customer_summary") {
    const res = await pool.query(
      "SELECT column_name, data_type FROM information_schema.columns WHERE table_name = 'customer_summary'"
    );
    return {
      contents: [
        {
          uri: request.params.uri,
          mimeType: "application/json",
          text: JSON.stringify(res.rows)
        }
      ]
    };
  }
  throw new Error("Resource not found");
});

// Register query tool
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "query_customer_data",
        description: "Queries safe customer details by customer ID",
        inputSchema: {
          type: "object",
          properties: {
            customerId: {
              type: "integer",
              description: "Customer ID"
            }
          },
          required: ["customerId"]
        }
      }
    ]
  };
});

// Handle execution safely via parameterized inputs
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "query_customer_data") {
    const customerId = request.params.arguments?.customerId;
    if (typeof customerId !== "number") {
      throw new Error("Invalid customerId input parameter type");
    }

    const res = await pool.query(
      "SELECT id, name, email, region FROM customer_summary WHERE id = $1 LIMIT 1",
      [customerId]
    );

    return {
      content: [
        {
          type: "text",
          text: JSON.stringify(res.rows)
        }
      ]
    };
  }
  throw new Error("Tool not found");
});

const transport = new StdioServerTransport();
await server.connect(transport);

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema
} from "@modelcontextprotocol/sdk/types.js";

// Fetch the API Token from local environment variables
const CRM_API_KEY = process.env.CRM_API_KEY;
const CRM_API_URL = process.env.CRM_API_URL || "https://api.crm.internal/v1";

if (!CRM_API_KEY) {
  console.error("Warning: CRM_API_KEY environment variable is not defined");
}

const server = new Server(
  {
    name: "crm-gateway-mcp",
    version: "1.0.0"
  },
  {
    capabilities: {
      tools: {}
    }
  }
);

// Register tools
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "get_crm_contact",
        description: "Retrieves CRM contact profile details by email address",
        inputSchema: {
          type: "object",
          properties: {
            email: {
              type: "string",
              description: "The email address of the customer contact"
            }
          },
          required: ["email"]
        }
      }
    ]
  };
});

// Handle execution
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "get_crm_contact") {
    const email = request.params.arguments?.email;
    if (!email || typeof email !== "string") {
      throw new Error("Email parameter is required and must be a string");
    }

    try {
      const response = await fetch(`${CRM_API_URL}/contacts?email=${encodeURIComponent(email)}`, {
        headers: {
          "Authorization": `Bearer ${CRM_API_KEY}`,
          "Accept": "application/json"
        }
      });

      if (!response.ok) {
        throw new Error(`CRM API responded with status: ${response.status}`);
      }

      const data = await response.json();

      // Filter sensitive details out to preserve context window and privacy
      const filteredData = {
        id: data.id,
        name: data.name,
        company: data.company,
        status: data.status,
        lastContacted: data.last_contacted
      };

      return {
        content: [
          {
            type: "text",
            text: JSON.stringify(filteredData)
          }
        ]
      };
    } catch (error: any) {
      return {
        content: [
          {
            type: "text",
            text: `Failed to query contact. API Error: ${error.message}`
          }
        ],
        isError: true
      };
    }
  }
  throw new Error("Tool not found");
});

const transport = new StdioServerTransport();
await server.connect(transport);

